  1→// Power-up system - extracted from game.js
  2→// All functions take `game` as first parameter
  3→
  4→import { TILE_TYPE, FEATURE_KEYS } from "./config.js";
  5→import {
  6→    isNormal,
  7→    createTile,
  8→    createCursedTile,
  9→    isCursed,
 10→    getDisplayValue,
 11→    getFontSize,
 12→} from "./tile-helpers.js";
 13→import { savePowerUpCounts, isFeatureUnlocked } from "./storage.js";
 14→import { updateMovesDisplay } from "./renderer.js";
 15→import { track } from "./tracker.js";
 16→
 17→const BASE_POWERUP_COST = 5;
 18→
 19→// Per-level buy counts, reset each level
 20→let levelBuyCounts = { hammer: 0, halve: 0, swap: 0, teleport: 0, wildcard: 0 };
 21→
 22→export function resetPowerUpBuyCounts() {
 23→    levelBuyCounts = { hammer: 0, halve: 0, swap: 0, teleport: 0, wildcard: 0 };
 24→}
 25→
 26→export function getPowerUpCost(type) {
 27→    return BASE_POWERUP_COST * Math.pow(2, levelBuyCounts[type]);
 28→}
 29→
 30→function incrementBuyCount(type) {
 31→    levelBuyCounts[type]++;
 32→}
 33→import { isTutorialActive, isTutorialPowerUpStep, isValidTutorialPowerUp, updateTutorialUI } from "./tutorial.js";
 34→
 35→export function setupPowerUps(game) {
 36→    const powerUpButtons = document.querySelectorAll(".power-up-btn.game");
 37→
 38→    powerUpButtons.forEach((button) => {
 39→        button.addEventListener("click", () => {
 40→            if (!game.gameActive) return;
 41→
 42→            const powerUpType = button.dataset.powerup;
 43→
 44→            if (!isPowerUpButtonVisible(game, powerUpType)) {
 45→                return;
 46→            }
 47→
 48→            if (isTutorialActive(game) && isTutorialPowerUpStep(game)) {
 49→                if (!isValidTutorialPowerUp(game, powerUpType)) {
 50→                    return;
 51→                }
 52→            }
 53→
 54→            if (game.activePowerUp === powerUpType) {
 55→                deactivatePowerUp(game);
 56→            } else {
 57→                const isBuying = getTotalPowerUpCount(game, powerUpType) <= 0;
 58→                if (isBuying) {
 59→                    if (game.powerUpMoveCost) {
 60→                        if (game.movesUsed >= game.maxMoves) return;
 61→                    } else if (game.coins < getPowerUpCost(powerUpType)) {
 62→                        const shopDialog = document.getElementById("shopDialog");
 63→                        if (shopDialog) {
 64→                            shopDialog.classList.remove("hidden");
 65→                            game.updateCoinsDisplays();
 66→                        }
 67→                        return;
 68→                    }
 69→                }
 70→                activatePowerUp(game, powerUpType, isBuying);
 71→            }
 72→        });
 73→    });
 74→}
 75→
 76→export function activatePowerUp(game, type, buying = false) {
 77→    if (isTutorialActive(game) && !isTutorialPowerUpStep(game)) {
 78→        return;
 79→    }
 80→
 81→    deactivatePowerUp(game);
 82→    game.activePowerUp = type;
 83→    game.powerUpBuying = buying;
 84→    game.powerUpSwapTiles = [];
 85→
 86→    const button = document.querySelector(`[data-powerup="${type}"]`);
 87→    if (button) {
 88→        button.classList.add("active");
 89→    }
 90→
 91→    if (isTutorialActive(game) && isTutorialPowerUpStep(game)) {
 92→        updateTutorialUI(game);
 93→    }
 94→}
 95→
 96→export function deactivatePowerUp(game) {
 97→    if (game.activePowerUp) {
 98→        const button = document.querySelector(`[data-powerup="${game.activePowerUp}"]`);
 99→        if (button) {
100→            button.classList.remove("active");
101→        }
102→    }
103→
104→    game.activePowerUp = null;
105→    game.powerUpBuying = false;
106→    game.powerUpSwapTiles = [];
107→}
108→
109→export function isPowerUpButtonVisible(game, powerUpType) {
110→    const idx = game.selectedPowerUps.indexOf(powerUpType);
111→    if (idx === -1) return false;
112→
113→    const unlockKeys = [FEATURE_KEYS.POWER_UP_1, FEATURE_KEYS.POWER_UP_2, FEATURE_KEYS.POWER_UP_3];
114→    let unlockedSlots = 0;
115→    for (const key of unlockKeys) {
116→        if (isFeatureUnlocked(key)) unlockedSlots++;
117→        else break;
118→    }
119→
120→    return idx < unlockedSlots;
121→}
122→
123→export function getVisiblePowerUpTypes(game) {
124→    return game.selectedPowerUps.filter((t) => isPowerUpButtonVisible(game, t));
125→}
126→
127→export function grantPowerUp(game, powerUpType) {
128→    game.powerUpCounts[powerUpType].transient++;
129→    updatePowerUpButtons(game);
130→}
131→
132→export function getTotalPowerUpCount(game, type) {
133→    const counts = game.powerUpCounts[type];
134→    const persistent = game.persistentPowerUpsEnabled ? counts.persistent : 0;
135→    return persistent + counts.transient;
136→}
137→
138→export function consumePowerUp(game, type) {
139→    game.powerUpUsedCounts[type]++;
140→
141→    if (game.powerUpBuying) {
142→        if (game.powerUpMoveCost) {
143→            game.movesUsed++;
144→            updateMovesDisplay(game);
145→        } else {
146→            const cost = getPowerUpCost(type);
147→            game.coins = Number(game.coins) - Number(cost);
148→            game.saveCoins();
149→            game.updateCoinsDisplays();
150→        }
151→        incrementBuyCount(type);
152→        game.updatePowerUpButtons();
153→        game.powerUpBuying = false;
154→        return;
155→    }
156→
157→    const counts = game.powerUpCounts[type];
158→    if (counts.transient > 0) {
159→        counts.transient--;
160→    } else if (game.persistentPowerUpsEnabled && counts.persistent > 0) {
161→        counts.persistent--;
162→        savePowerUpCounts({
163→            hammer: game.powerUpCounts.hammer.persistent,
164→            halve: game.powerUpCounts.halve.persistent,
165→            swap: game.powerUpCounts.swap.persistent,
166→            teleport: game.powerUpCounts.teleport.persistent,
167→            wildcard: game.powerUpCounts.wildcard.persistent,
168→        });
169→    }
170→}
171→
172→export function grantFormationPowerUp(game, formationType) {
173→    if (!game.formationPowerUpRewards) return;
174→
175→    const formationToPowerUp = {
176→        "L-formation": "hammer",
177→        "T-formation": "halve",
178→        line_5_horizontal: "swap",
179→        line_5_vertical: "swap",
180→    };
181→
182→    const powerUpType = formationToPowerUp[formationType];
183→    if (!powerUpType) return;
184→
185→    if (!isPowerUpButtonVisible(game, powerUpType)) return;
186→
187→    grantPowerUp(game, powerUpType);
188→    showPowerUpRewardAnimation(game, powerUpType);
189→}
190→
191→export function showPowerUpRewardAnimation(game, powerUpType) {
192→    const motivationalWords = ["Great!", "Awesome!", "Wow!", "Amazing!", "Nice!", "Super!"];
193→    const randomWord = motivationalWords[Math.floor(Math.random() * motivationalWords.length)];
194→
195→    const powerUpIcons = {
196→        hammer: "🔨",
197→        halve: "✂️",
198→        swap: "🔄",
199→        teleport: "🚀",
200→        wildcard: "✨",
201→    };
202→    const icon = powerUpIcons[powerUpType];
203→
204→    const container = document.createElement("div");
205→    container.className = "formation-powerup-animation";
206→
207→    const headline = document.createElement("stroked-text");
208→    headline.className = "formation-powerup-headline";
209→    headline.setAttribute("text", randomWord);
210→    headline.setAttribute("font-size", "48");
211→    headline.setAttribute("stroke-width", "12");
212→    headline.setAttribute("fill", "#FFD700");
213→    headline.setAttribute("stroke", "#333");
214→
215→    const subtitleContainer = document.createElement("div");
216→    subtitleContainer.className = "formation-powerup-subtitle";
217→
218→    const plusOneText = document.createElement("stroked-text");
219→    plusOneText.setAttribute("text", "+1");
220→    plusOneText.setAttribute("font-size", "36");
221→    plusOneText.setAttribute("stroke-width", "10");
222→    plusOneText.setAttribute("fill", "#FFFFFF");
223→    plusOneText.setAttribute("stroke", "#333");
224→
225→    const iconText = document.createElement("stroked-text");
226→    iconText.setAttribute("text", icon);
227→    iconText.setAttribute("font-size", "36");
228→    iconText.setAttribute("stroke-width", "6");
229→
230→    subtitleContainer.appendChild(plusOneText);
231→    subtitleContainer.appendChild(iconText);
232→
233→    container.appendChild(headline);
234→    container.appendChild(subtitleContainer);
235→
236→    const gameContainer = document.getElementById("game-container");
237→    if (gameContainer) {
238→        gameContainer.appendChild(container);
239→        setTimeout(() => {
240→            container.remove();
241→        }, 2000);
242→    }
243→}
244→
245→export function showPowerUps(game) {
246→    const powerUpsContainer = document.querySelector(".power-ups");
247→    if (powerUpsContainer) {
248→        powerUpsContainer.style.visibility = "";
249→    }
250→    const allButtons = document.querySelectorAll(".power-up-btn.game");
251→    allButtons.forEach((btn) => {
252→        btn.style.display = game.selectedPowerUps.includes(btn.dataset.powerup) ? "" : "none";
253→    });
254→}
255→
256→export function hidePowerUps(game) {
257→    const powerUpsContainer = document.querySelector(".power-ups");
258→    if (powerUpsContainer) {
259→        powerUpsContainer.style.visibility = "hidden";
260→    }
261→}
262→
263→export function updatePowerUpButtons(game) {
264→    const powerUpButtons = document.querySelectorAll(".power-up-btn.game");
265→
266→    powerUpButtons.forEach((button) => {
267→        const powerUpType = button.dataset.powerup;
268→
269→        if (!isPowerUpButtonVisible(game, powerUpType)) {
270→            button.classList.add("locked");
271→            button.disabled = true;
272→            button.title = "Unlock by progressing through levels";
273→            const existingIndicator = button.querySelector(".use-indicator");
274→            if (existingIndicator) {
275→                existingIndicator.remove();
276→            }
277→            return;
278→        }
279→
280→        button.classList.remove("locked");
281→        button.disabled = false;
282→
283→        const counts = game.powerUpCounts[powerUpType];
284→        const persistent = game.persistentPowerUpsEnabled ? counts.persistent : 0;
285→        const transient = counts.transient;
286→        const total = persistent + transient;
287→
288→        const existingIndicator = button.querySelector(".use-indicator, .cost-indicator");
289→        if (existingIndicator) {
290→            existingIndicator.remove();
291→        }
292→
293→        if (total <= 0) {
294→            button.classList.remove("can-purchase");
295→            const indicator = document.createElement("div");
296→            indicator.className = "cost-indicator";
297→
298→            if (game.powerUpMoveCost) {
299→                const amountBox = document.createElement("div");
300→                amountBox.className = "cost-amount move";
301→                amountBox.textContent = "-1 Move";
302→                indicator.appendChild(amountBox);
303→                button.appendChild(indicator);
304→                button.title = `${button.title.split(" - ")[0]} - Buy for 1 move`;
305→            } else {
306→                const cost = getPowerUpCost(powerUpType);
307→                const amountBox = document.createElement("div");
308→                amountBox.className = "cost-amount";
309→                amountBox.textContent = cost;
310→
311→                const coinIcon = document.createElement("img");
312→                coinIcon.src = "assets/shop/coin.png";
313→                coinIcon.className = "cost-coin-icon";
314→                coinIcon.alt = "Coins";
315→
316→                indicator.appendChild(amountBox);
317→                indicator.appendChild(coinIcon);
318→                button.appendChild(indicator);
319→                button.title = `${button.title.split(" - ")[0]} - Buy for ${cost} coins`;
320→            }
321→        } else {
322→            button.classList.remove("can-purchase");
323→            const indicator = document.createElement("div");
324→            indicator.className = "use-indicator";
325→
326→            const strokedText = document.createElement("stroked-text");
327→            strokedText.setAttribute("text", total);
328→            strokedText.setAttribute("font-size", "26");
329→            strokedText.setAttribute("width", "40");
330→            strokedText.setAttribute("height", "40");
331→            strokedText.setAttribute("svg-style", "width: 100%; height: 100%;");
332→
333→            if (transient > 0) {
334→                indicator.classList.add("transient-count");
335→            }
336→
337→            indicator.appendChild(strokedText);
338→            button.appendChild(indicator);
339→
340→            button.classList.remove("disabled");
341→            const baseTitle = button.title.split(" - ")[0];
342→            button.title = `${baseTitle} - ${total} uses left`;
343→        }
344→    });
345→}
346→
347→export function handlePowerUpAction(game, row, col, element) {
348→    const tile = game.board[row][col];
349→
350→    switch (game.activePowerUp) {
351→        case "hammer":
352→            if (!tile) return;
353→            const allowedTypes = [TILE_TYPE.NORMAL];
354→            if (!allowedTypes.includes(tile.type)) return;
355→            usePowerUpHammer(game, row, col, element);
356→            break;
357→        case "halve":
358→            usePowerUpHalve(game, row, col, element);
359→            break;
360→        case "swap":
361→        case "teleport":
362→            return false;
363→        case "wildcard":
364→            usePowerUpWildcard(game, row, col, element);
365→            break;
366→    }
367→}
368→
369→export function usePowerUpHammer(game, row, col, element) {
370→    game.resetHintTimer();
371→
372→    consumePowerUp(game, "hammer");
373→    updatePowerUpButtons(game);
374→
375→    track("power_up_used", {
376→        level: game.currentLevel,
377→        power_up_type: "hammer",
378→        remaining_moves: game.maxMoves - game.movesUsed,
379→        uses_remaining: getTotalPowerUpCount(game, "hammer"),
380→    });
381→
382→    game.animating = true;
383→
384→    element.style.transition = "transform 0.3s ease, opacity 0.3s ease";
385→    element.style.opacity = "0";
386→    element.style.transform = "scale(0)";
387→
388→    setTimeout(() => {
389→        game.board[row][col] = null;
390→        game.dropGems();
391→        deactivatePowerUp(game);
392→    }, 300);
393→}
394→
395→export function usePowerUpHalve(game, row, col, element) {
396→    const tile = game.board[row][col];
397→    const isCursedTile = isCursed(tile);
398→    const currentValue = tile && (tile.type === TILE_TYPE.NORMAL || isCursedTile) ? tile.value : null;
399→
400→    if (currentValue && currentValue > 1) {
401→        game.resetHintTimer();
402→
403→        consumePowerUp(game, "halve");
404→        updatePowerUpButtons(game);
405→
406→        track("power_up_used", {
407→            level: game.currentLevel,
408→            power_up_type: "halve",
409→            remaining_moves: game.maxMoves - game.movesUsed,
410→            uses_remaining: getTotalPowerUpCount(game, "halve"),
411→        });
412→
413→        game.animating = true;
414→
415→        const halvedValue = currentValue - 1;
416→
417→        if (isCursedTile) {
418→            game.board[row][col] = createCursedTile(halvedValue, tile.cursedMovesRemaining);
419→        } else {
420→            game.board[row][col] = createTile(halvedValue);
421→        }
422→
423→        game.levelGoals.forEach((goal) => {
424→            if (goal.tileValue === halvedValue) {
425→                goal.created += 1;
426→            }
427→        });
428→
429→        const displayValue = getDisplayValue(halvedValue);
430→        const fontSize = getFontSize(displayValue);
431→        element.innerHTML = `<span style="font-size: ${fontSize}cqw">${displayValue}</span>`;
432→        element.className = `gem tile-${halvedValue}`;
433→        if (isCursedTile) {
434→            element.classList.add("cursed-tile");
435→            element.dataset.cursedMoves = tile.cursedMovesRemaining;
436→        }
437→        element.dataset.row = row;
438→        element.dataset.col = col;
439→
440→        element.style.transform = "scale(1.2)";
441→        setTimeout(() => {
442→            element.style.transform = "scale(1)";
443→            game.updateGoalDisplay(false);
444→
445→            setTimeout(() => {
446→                game.animating = false;
447→                game.processMatches();
448→            }, 100);
449→        }, 200);
450→
451→        deactivatePowerUp(game);
452→    }
453→}
454→
455→export function usePowerUpWildcard(game, row, col, element) {
456→    const tile = game.board[row][col];
457→
458→    if (!tile || !isNormal(tile)) return;
459→
460→    game.resetHintTimer();
461→
462→    consumePowerUp(game, "wildcard");
463→    updatePowerUpButtons(game);
464→
465→    track("power_up_used", {
466→        level: game.currentLevel,
467→        power_up_type: "wildcard",
468→        remaining_moves: game.maxMoves - game.movesUsed,
469→        uses_remaining: getTotalPowerUpCount(game, "wildcard"),
470→    });
471→
472→    game.animating = true;
473→
474→    game.board[row][col] = {
475→        type: TILE_TYPE.JOKER,
476→        value: null,
477→        targetValue: null,
478→        specialType: null,
479→        hasBeenSwapped: false,
480→    };
481→
482→    element.style.transition = "transform 0.3s ease";
483→    element.style.transform = "scale(1.3)";
484→    setTimeout(() => {
485→        element.style.transform = "scale(1)";
486→        game.renderBoard();
487→        game.animating = false;
488→    }, 300);
489→
490→    deactivatePowerUp(game);
491→}
