377→/**
378→ * Get the tiles that would be matched if a swap is performed
379→ * Used by swap preview during drag
380→ * @param {Match3Game} game - The game instance
381→ * @param {number} row1 - First tile row
382→ * @param {number} col1 - First tile column
383→ * @param {number} row2 - Second tile row
384→ * @param {number} col2 - Second tile column
385→ * @returns {Array<{row: number, col: number}>} Array of tile positions in PRE-SWAP coordinates
386→ */
387→export function getMatchTilesForSwap(game, row1, col1, row2, col2) {
388→    // Save original board reference and flags (don't modify the original)
389→    const originalBoard = game.board;
390→    const originalIsUserSwap = game.isUserSwap;
391→    const originalLastSwapPosition = game.lastSwapPosition;
392→
393→    // Create a working copy for the evaluation
394→    game.board = originalBoard.map((row) => row.map((tile) => (tile ? { ...tile } : null)));
395→
396→    // Swap tiles on the working copy
397→    const temp = game.board[row1][col1];
398→    game.board[row1][col1] = game.board[row2][col2];
399→    game.board[row2][col2] = temp;
400→
401→    // Set flag for joker activation
402→    game.isUserSwap = true;
403→    game.lastSwapPosition = {
404→        row: row2,
405→        col: col2,
406→        movedFrom: { row: row1, col: col1 },
407→    };
408→
409→    // Check if this swap creates matches
410→    const hasMatches = hasMatchesForSwap(game, row1, col1, row2, col2);
411→
412→    let matchTiles = [];
413→    if (hasMatches) {
414→        // Get detailed match information
415→        const matches = findMatches(game);
416→
417→        // Only include matches that involve the actively dragged tile
418→        // The dragged tile starts at (row1, col1) and after swap is at (row2, col2)
419→        const relevantMatches = matches.filter((match) =>
420→            match.tiles.some((tile) => tile.row === row2 && tile.col === col2),
421→        );
422→
423→        // Collect tiles from relevant matches only
424→        // Translate post-swap positions back to pre-swap positions for display
425→        for (const match of relevantMatches) {
426→            for (const tile of match.tiles) {
427→                let displayRow = tile.row;
428→                let displayCol = tile.col;
429→
430→                // If this tile is at a swap position, translate it back
431→                if (tile.row === row1 && tile.col === col1) {
432→                    // This tile is at position 1 after swap, so it was at position 2 before
433→                    displayRow = row2;
434→                    displayCol = col2;
435→                } else if (tile.row === row2 && tile.col === col2) {
436→                    // This tile is at position 2 after swap, so it was at position 1 before
437→                    displayRow = row1;
438→                    displayCol = col1;
439→                }
440→
441→                matchTiles.push({ row: displayRow, col: displayCol });
442→            }
443→        }
444→    }
445→
446→    // Restore original board reference (not a copy)
447→    game.board = originalBoard;
448→    game.isUserSwap = originalIsUserSwap;
449→    game.lastSwapPosition = originalLastSwapPosition;
450→
451→    return matchTiles;
452→}
