 26→export function checkLevelComplete(game) {
 27→    // Don't check while animations are running
 28→    if (game.animating) return;
 29→
 30→    const allGoalsComplete = game.levelGoals.every((goal) => {
 31→        if (goal.goalType === "current") {
 32→            return goal.current >= goal.target;
 33→        } else if (goal.goalType === "blocked") {
 34→            return goal.current >= goal.target;
 35→        } else if (goal.goalType === "cursed") {
 36→            return goal.current >= goal.target;
 37→        } else if (goal.goalType === "score") {
 38→            return goal.current >= goal.target;
 39→        } else {
 40→            return goal.created >= goal.target;
 41→        }
 42→    });
 43→    const nextBtn = document.getElementById("nextBtn");
 44→
 45→    if (allGoalsComplete) {
 46→        game.gameActive = false;
 47→        game.deactivatePowerUp();
 48→
 49→        // Increment streak (capped at 3) - only if streak feature is unlocked
 50→        if (isFeatureUnlocked(FEATURE_KEYS.STREAK)) {
 51→            game.currentStreak = Math.min(game.currentStreak + 1, 3);
 52→            saveStreak(game.currentStreak);
 53→        }
 54→
 55→        // Increment super streak (no cap) - only if board_upgrades feature is unlocked
 56→        if (isFeatureUnlocked(FEATURE_KEYS.SUPER_STREAK)) {
 57→            game.superStreak = game.superStreak + 1;
 58→            saveSuperStreak(game.superStreak);
 59→        }
 60→
 61→        // Award 50 coins for completing the level
 62→        const currentCoins = loadCoins();
 63→        const newCoins = currentCoins + 50;
 64→        saveCoins(newCoins);
 65→        game.coins = newCoins;
 66→
 67→        // Award one random unlocked power-up (only if persistent power-ups are enabled)
 68→        if (game.persistentPowerUpsEnabled) {
 69→            const unlockedPowerUps = game.getVisiblePowerUpTypes();
 70→
 71→            if (unlockedPowerUps.length > 0) {
 72→                const randomPowerUp = unlockedPowerUps[Math.floor(Math.random() * unlockedPowerUps.length)];
 73→                game.powerUpCounts[randomPowerUp].persistent++;
 74→                savePowerUpCounts({
 75→                    hammer: game.powerUpCounts.hammer.persistent,
 76→                    halve: game.powerUpCounts.halve.persistent,
 77→                    swap: game.powerUpCounts.swap.persistent,
 78→                    teleport: game.powerUpCounts.teleport.persistent,
 79→                    wildcard: game.powerUpCounts.wildcard.persistent,
 80→                });
 81→
 82→                // Show the power-up reward in the UI
 83→                const powerUpReward = document.getElementById("powerUpReward");
 84→                const powerUpRewardIcon = document.getElementById("powerUpRewardIcon");
 85→
 86→                if (powerUpReward && powerUpRewardIcon) {
 87→                    const powerUpIcons = {
 88→                        hammer: "🔨",
 89→                        halve: "✂️",
 90→                        swap: "🔄",
 91→                    };
 92→
 93→                    powerUpRewardIcon.textContent = powerUpIcons[randomPowerUp];
 94→                    powerUpReward.style.display = "flex";
 95→                }
 96→            }
 97→        }
 98→
 99→        // Hide power-ups and show control buttons
100→        game.hidePowerUps();
101→        game.showControls();
102→
103→        // Show only the next button with reward container
104→        const restartBtn = document.getElementById("restartBtn");
105→        const continueBtn = document.getElementById("continueBtn");
106→        const nextLevelContainer = document.getElementById("nextLevelContainer");
107→        if (nextLevelContainer) nextLevelContainer.style.display = "block";
108→        if (restartBtn) restartBtn.style.display = "none";
109→        if (continueBtn) continueBtn.style.display = "none";
110→        setTimeout(() => {
111→            // Tracking happens in showLevelSolved
112→            game.showLevelSolved();
113→        }, 500);
114→    } else if (game.movesUsed >= game.maxMoves && !game.hasMatches()) {
115→        // Only trigger game over if there are no more cascading matches AND no animations running
116→        game.gameActive = false;
117→        game.deactivatePowerUp();
118→
119→        // Hide power-ups
120→        game.hidePowerUps();
121→
122→        // Store fail reason for later use
123→        game.failReason = "No moves left";
124→
125→        // Show extra moves dialog after a delay to let final animations settle
126→        setTimeout(() => {
127→            if (game.extraMovesUsed) {
128→                // Show level failed screen (heart decrease and streak reset happens in showLevelFailed)
129→                game.showLevelFailed(game.failReason);
130→            } else {
131→                // Show extra moves dialog (first time)
132→                // Note: Streak is NOT reset here - only when level fully fails
133→                // Note: Hearts are NOT decreased here - only on full level loss
134→                game.showExtraMovesDialog();
135→            }
136→        }, 800);
137→    } else if (game.gameActive) {
138→        // Check if no valid moves are possible even if moves remain
139→        // Skip check if allowNonMatchingSwaps - always have moves available
140→        const hasValidMoves = game.allowNonMatchingSwaps || findBestSwap(game) !== null;
141→        if (!hasValidMoves && !game.hasMatches()) {
142→            // Game over: no valid moves possible - immediately show level failed (no extra moves option)
143→            game.gameActive = false;
144→            game.deactivatePowerUp();
145→            game.hidePowerUps();
146→
147→            setTimeout(() => {
148→                game.showLevelFailed("No moves possible");
149→            }, 800);
150→        } else {
151→            game.hideControls();
152→            // Show power-ups during active gameplay
153→            game.showPowerUps();
154→        }
155→    }
156→}
