158→export function updateTileCounts(game) {
159→    // Count tiles currently on the board for "current" type goals
160→    game.tileCounts = {};
161→    for (let row = 0; row < game.boardHeight; row++) {
162→        for (let col = 0; col < game.boardWidth; col++) {
163→            const tile = game.board[row][col];
164→            if (isNormal(tile)) {
165→                const value = getTileValue(tile);
166→                game.tileCounts[value] = (game.tileCounts[value] || 0) + 1;
167→            }
168→        }
169→    }
170→
171→    // Update current counts for "current" type goals
172→    game.levelGoals.forEach((goal) => {
173→        if (goal.goalType === "current") {
174→            goal.current = game.tileCounts[goal.tileValue] || 0;
175→        }
176→    });
177→}
