179→export function countBlockedLevelTiles(game) {
180→    if (!game.blockedTiles || game.blockedTiles.length === 0) return 0;
181→
182→    let count = 0;
183→    game.blockedTiles.forEach((blockedPos) => {
184→        // Handle rectangular blocks (with width and height)
185→        if (blockedPos.width !== undefined && blockedPos.height !== undefined) {
186→            count += blockedPos.width * blockedPos.height;
187→        } else if (blockedPos.row !== undefined && blockedPos.col !== undefined) {
188→            const colArray = Array.isArray(blockedPos.col) ? blockedPos.col : [blockedPos.col];
189→            count += colArray.length;
190→        } else if (blockedPos.row !== undefined && blockedPos.col === undefined) {
191→            if (blockedPos.row < game.boardHeight) {
192→                count += game.boardWidth;
193→            }
194→        } else if (blockedPos.col !== undefined && blockedPos.row === undefined) {
195→            if (blockedPos.col < game.boardWidth) {
196→                count += game.boardHeight;
197→            }
198→        }
199→    });
200→    return count;
201→}
202→
203→export function countBlockedTiles(game) {
204→    if (!game.board || !game.board[0]) return 0;
205→
206→    let count = 0;
207→    const countedRects = new Set(); // Track rectangular blocks we've already counted
208→
209→    for (let row = 0; row < game.boardHeight; row++) {
210→        for (let col = 0; col < game.boardWidth; col++) {
211→            const tile = game.board[row][col];
212→
213→            // Handle merge-count tiles specially - count only cells that still need clearing
214→            if (isBlockedWithMergeCount(tile)) {
215→                const cellKey = `${row}_${col}`;
216→                // Only count this cell if it still needs clearing
217→                if (tile.cellMergeCounts[cellKey] > 0) {
218→                    count++;
219→                }
220→            }
221→            // Handle regular blocked tiles (not merge-count)
222→            else if (isBlocked(tile) || isBlockedWithLife(tile) || isBlockedMovable(tile)) {
223→                // If it's a rectangular block, only count it once
224→                if (tile.isRectangular) {
225→                    if (!countedRects.has(tile.rectId)) {
226→                        countedRects.add(tile.rectId);
227→                        count += tile.rectWidth * tile.rectHeight;
228→                    }
229→                } else {
230→                    count++;
231→                }
232→            }
233→        }
234→    }
235→    return count;
236→}
