238→export function updateBlockedTileGoals(game) {
239→    const currentBlockedCount = countBlockedTiles(game);
240→    const totalBlockedTiles = game.initialBlockedTileCount;
241→    const clearedCount = totalBlockedTiles - currentBlockedCount;
242→
243→    game.levelGoals.forEach((goal) => {
244→        if (goal.goalType === "blocked") {
245→            goal.current = clearedCount;
246→            goal.target = totalBlockedTiles;
247→        }
248→    });
249→}
