293→export function decrementCursedTileTimers(game) {
294→    // Decrement move counter for cursed tiles, EXCEPT those created this turn
295→    const cursedTilesToRemove = [];
296→    const cursedTilesToImplode = [];
297→    let hasDecrementedAny = false;
298→
299→    // Scan entire board for cursed tiles
300→    for (let row = 0; row < game.boardHeight; row++) {
301→        for (let col = 0; col < game.boardWidth; col++) {
302→            const tile = game.board[row][col];
303→            if (tile && isCursed(tile)) {
304→                // Skip tiles created this turn, but clear the flag for next turn
305→                if (tile.createdThisTurn) {
306→                    tile.createdThisTurn = false;
307→                    continue;
308→                }
309→
310→                // Decrement the timer
311→                tile.cursedMovesRemaining--;
312→                hasDecrementedAny = true;
313→
314→                if (tile.cursedMovesRemaining <= 0) {
315→                    // Check if this cursed goal has implode enabled
316→                    const value = getTileValue(tile);
317→                    const cursedGoal = game.levelGoals.find(
318→                        (goal) => goal.goalType === "cursed" && goal.tileValue === value
319→                    );
320→
321→                    if (cursedGoal && cursedGoal.implode) {
322→                        cursedTilesToImplode.push({ row, col });
323→                    } else {
324→                        cursedTilesToRemove.push({ row, col });
325→                    }
326→                }
327→            }
328→        }
329→    }
330→
331→    // Re-render to update counters before animating removals
332→    if (hasDecrementedAny) {
333→        game.renderBoard();
334→    }
335→
336→    // Trigger animations if tiles expired
337→    if (cursedTilesToRemove.length > 0 || cursedTilesToImplode.length > 0) {
338→        animateCursedExpiration(game, cursedTilesToRemove, cursedTilesToImplode, () => game.dropGems());
339→    }
340→}
