298→ * @param {Object} game - The game instance
299→ * @param {string} dialogType - The dialog type being shown
300→ * @returns {string} HTML string for goal visuals
301→ */
302→function generateGoalVisualsHTML(game, dialogType) {
303→    if (!game || !game.levelGoals) return "";
304→
305→    // Filter goals that match this dialog type
306→    const relevantGoals = game.levelGoals.filter((goal) => {
307→        if (dialogType === "created" && goal.goalType === "created") return true;
308→        if (dialogType === "current" && goal.goalType === "current") return true;
309→        if (dialogType === "blocked" && goal.goalType === "blocked" && !hasLifeBasedBlockedTiles(game.blockedTiles))
310→            return true;
311→        if (dialogType === "cursed" && goal.goalType === "cursed" && !goal.implode) return true;
312→        if (dialogType === "cursed_implode" && goal.goalType === "cursed" && goal.implode) return true;
313→        if (dialogType === "score" && goal.goalType === "score") return true;
314→        return false;
315→    });
316→
317→    if (relevantGoals.length === 0) return "";
318→
