333→export function showGoalDialog(dialogType, game, onClose) {
334→    const dialog = GOAL_DIALOGS[dialogType];
335→    if (!dialog) {
336→        console.error(`Unknown dialog type: ${dialogType}`);
337→        if (onClose) onClose();
338→        return;
339→    }
340→
341→    // Create dialog overlay
342→    const overlay = document.createElement("div");
343→    overlay.className = "goal-dialog-overlay";
344→    overlay.id = "goalDialog";
345→
346→    // Generate goal visuals HTML
347→    const goalsHTML = generateGoalVisualsHTML(game, dialogType);
348→
349→    // Create dialog content
