  3→import { TILE_TYPE } from "./config.js";
  4→
  5→/**
  6→ * Create a normal tile with optional special properties
  7→ * @param {number} value - The tile's internal value
  8→ * @param {string|null} specialType - Special tile type: "freeswap", "sticky_freeswap",
  9→ *                                     "freeswap_horizontal", "freeswap_vertical", "hammer", "halver", or null
 10→ * @param {Object} options - Additional options
 11→ * @param {boolean} options.transferStickyFreeSwap - Whether to transfer sticky free swap ability
 12→ * @param {boolean|null} options.isHorizontal - For directional free swaps: true=horizontal, false=vertical, null=use config
 13→ * @returns {Object} The created tile
 14→ */
 15→export function createTile(value, specialType = null, options = {}) {
 16→    const { transferStickyFreeSwap = false, isHorizontal = null } = options;
 17→
 18→    // Base tile
 19→    const tile = {
 20→        type: TILE_TYPE.NORMAL,
 21→        value: value,
 22→        specialType: null,
 23→        hasBeenSwapped: false,
 24→    };
 25→
 26→    // Apply special type
 27→    if (specialType) {
 28→        tile.specialType = specialType;
 29→
 30→        // For directional free swaps, override with isHorizontal option if provided
 31→        if ((specialType === "freeswap_horizontal" || specialType === "freeswap_vertical") && isHorizontal !== null) {
 32→            tile.specialType = isHorizontal ? "freeswap_horizontal" : "freeswap_vertical";
 33→        }
 34→    }
 35→
 36→    // Transfer sticky free swap ability if requested (for cascading merges)
 37→    if (transferStickyFreeSwap) {
 38→        tile.specialType = "sticky_freeswap";
 39→    }
 40→
 41→    return tile;
 42→}
 43→
 44→export function createBlockedTile(immovable = true) {
 45→    return {
 46→        type: TILE_TYPE.BLOCKED,
 47→        value: null,
 48→        immovable: immovable,
