  1→/**
  2→ * tutorial.js
  3→ *
  4→ * FTUX (First Time User Experience) tutorial system
  5→ * Guides users through specific swap sequences with animated hand and hint text
  6→ */
  7→
  8→/**
  9→ * Initialize tutorial from level config
 10→ * @param {Match3Game} game - Game instance
 11→ */
 12→export function initTutorial(game) {
 13→    const level = game.levelConfig;
 14→
 15→    if (!level.tutorialSwaps || level.tutorialSwaps.length === 0) {
 16→        game.tutorialState = null;
 17→        return;
 18→    }
 19→
 20→    game.tutorialState = {
 21→        active: true,
 22→        currentStep: 0,
 23→        swaps: level.tutorialSwaps,
 24→    };
 25→
 26→    // Create DOM elements if they don't exist
 27→    if (!game.tutorialElements) {
 28→        const overlay = document.getElementById("tutorialOverlay");
 29→        const hand = document.getElementById("tutorialHand");
 30→        const hintBox = document.querySelector(".tutorial-hint-box");
 31→        const hintText = document.getElementById("tutorialHintText");
 32→
 33→        game.tutorialElements = {
 34→            overlay,
 35→            hand,
 36→            hintBox,
 37→            hintText,
 38→        };
 39→    }
 40→}
 41→
 42→/**
 43→ * Check if tutorial is currently active
 44→ * @param {Match3Game} game - Game instance
 45→ * @returns {boolean} True if tutorial is active
 46→ */
 47→export function isTutorialActive(game) {
 48→    return game.tutorialState && game.tutorialState.active;
 49→}
 50→
 51→/**
 52→ * Get the current tutorial swap definition
 53→ * @param {Match3Game} game - Game instance
 54→ * @returns {Object|null} Current swap object or null
 55→ */
 56→export function getCurrentTutorialSwap(game) {
 57→    if (!isTutorialActive(game)) return null;
 58→
 59→    const step = game.tutorialState.currentStep;
 60→    return game.tutorialState.swaps[step] || null;
 61→}
 62→
 63→/**
 64→ * Check if the current tutorial step is a power-up step
 65→ * @param {Match3Game} game - Game instance
 66→ * @returns {boolean} True if current step is power-up step
 67→ */
 68→export function isTutorialPowerUpStep(game) {
 69→    const currentSwap = getCurrentTutorialSwap(game);
 70→    if (!currentSwap) return false;
 71→
 72→    // Check if step has a powerUp property
 73→    return currentSwap.powerUp !== undefined;
 74→}
 75→
 76→/**
 77→ * Check if a swap matches the current tutorial step (bidirectional)
 78→ * @param {Match3Game} game - Game instance
 79→ * @param {number} row1 - First tile row
 80→ * @param {number} col1 - First tile column
 81→ * @param {number} row2 - Second tile row
 82→ * @param {number} col2 - Second tile column
 83→ * @returns {boolean} True if swap is valid for tutorial
 84→ */
 85→export function isValidTutorialSwap(game, row1, col1, row2, col2) {
 86→    const currentSwap = getCurrentTutorialSwap(game);
 87→    if (!currentSwap) return false;
 88→
 89→    // If this is a tap-only step, swapping is not valid
 90→    if (!currentSwap.from || !currentSwap.to) return false;
 91→
 92→    const from = currentSwap.from;
 93→    const to = currentSwap.to;
 94→
 95→    // Check forward direction (from → to)
 96→    const matchesForward = row1 === from.row && col1 === from.col && row2 === to.row && col2 === to.col;
 97→
 98→    // Check reverse direction (to → from)
 99→    const matchesReverse = row1 === to.row && col1 === to.col && row2 === from.row && col2 === from.col;
100→
101→    return matchesForward || matchesReverse;
102→}
