404→export function calculateMiddlePositions(game, tiles, group = null) {
405→    const positions = [];
406→    const length = tiles.length;
407→
408→    // Special handling for T and L formations
409→    if (group && (group.direction === "T-formation" || group.direction === "L-formation")) {
410→        // For special formations, the "middle" position is the intersection
411→        positions.push(group.intersection);
412→        return positions;
413→    }
414→
415→    // Special handling for block formations
416→    if (group && group.direction === "block_4_formation") {
417→        // For block formations, the "middle" positions are the two intersections
418→        return group.intersections;
419→    }
420→
421→    // Special handling for 5-tile lines (should create 1 tile with 4x value)
422→    if (group && (group.direction === "line_5_horizontal" || group.direction === "line_5_vertical")) {
423→        // 5 tiles: middle position only (creates 1 tile with 4x value)
424→        positions.push(tiles[2]);
425→        return positions;
426→    }
427→
428→    // Regular match logic
429→    if (length === 3) {
430→        // 3 tiles: middle position (creates 1 tile with 2x value)
431→        positions.push(tiles[1]);
432→    } else if (length === 4) {
433→        // 4 tiles: two middle positions (creates 2 tiles with 2x value)
434→        positions.push(tiles[1]);
435→        positions.push(tiles[2]);
436→    } else if (length >= 5) {
437→        // 5+ tiles: single middle position (creates 1 tile with 4x value)
438→        positions.push(tiles[Math.floor(length / 2)]);
439→    }
440→
441→    return positions;
442→}
