455→export function unblockAdjacentTiles(game, matchGroups) {
456→    const blockedTilesToRemove = [];
457→    const goalTilesToDamage = [];
458→    const cellsToDecrement = new Set(); // Track individual cells to decrement for merge-count blocks
459→
460→    matchGroups.forEach((group) => {
461→        // Track which blocked tiles have been hit by this match group
462→        const hitInThisGroup = new Set();
463→
464→        // Get where the new merged tile(s) will be created
465→        let targetPositions = [];
466→        if (group.direction === "T-formation" || group.direction === "L-formation") {
467→            targetPositions.push(group.intersection);
468→        } else if (group.direction === "block_4_formation") {
469→            targetPositions.push(...group.intersections);
470→        } else {
471→            const middlePositions = calculateMiddlePositions(game, group.tiles, group);
472→            targetPositions.push(...middlePositions);
473→        }
474→
475→        // Calculate the damage value from this match (the value of tiles being matched, not the merged result)
476→        const damageValue = getDisplayValue(group.value);
477→
478→        // Check each tile in the original match for adjacent blocked/goal tiles
479→        group.tiles.forEach((matchTile) => {
480→            const adjacentPositions = [
481→                { row: matchTile.row - 1, col: matchTile.col }, // Up
482→                { row: matchTile.row + 1, col: matchTile.col }, // Down
483→                { row: matchTile.row, col: matchTile.col - 1 }, // Left
484→                { row: matchTile.row, col: matchTile.col + 1 }, // Right
485→            ];
486→
487→            adjacentPositions.forEach((pos) => {
488→                // Check bounds
