515→
516→                            targetPositions.forEach((target) => {
517→                                const distance = Math.abs(pos.row - target.row) + Math.abs(pos.col - target.col);
518→                                if (distance < closestDistance) {
519→                                    closestDistance = distance;
520→                                    closestTarget = target;
521→                                }
522→                            });
523→
