260→        let formationScore = 0;
261→        const direction = match.direction;
262→
263→        if (direction === "line_5_horizontal" || direction === "line_5_vertical") {
264→            formationScore = 1000;
265→        } else if (direction === "T-formation" || direction === "L-formation") {
266→            formationScore = 800;
267→        } else if (direction === "line_4_horizontal" || direction === "line_4_vertical") {
268→            formationScore = 600;
269→        } else if (direction === "block_4_formation") {
270→            formationScore = 500;
271→        } else {
272→            formationScore = 300; // 3-line matches
273→        }
274→
275→        maxFormationScore = Math.max(maxFormationScore, formationScore);
276→
277→        // Count tiles cleared
278→        totalTilesCleared += match.tiles.length;
279→
280→        // Track max value
281→        maxValue = Math.max(maxValue, match.value);
282→
283→        // Check for special tile creation based on formation type
284→        if (direction === "T-formation" || direction === "L-formation" || direction.includes("line_5")) {
285→            hasSpecialTile = true;
286→        }
287→    }
288→
289→    // Calculate goal progress
290→    if (game.levelGoals && game.levelGoals.length > 0) {
291→        for (const match of matches) {
292→            for (const goal of game.levelGoals) {
293→                // Check if this match contributes to any goals
294→                if (goal.tileValue === match.value) {
295→                    if (goal.goalType === "created") {
296→                        goalProgress += match.tiles.length;
297→                    } else if (goal.goalType === "current") {
298→                        goalProgress += 1;
299→                    }
300→                }
301→            }
302→        }
303→    }
304→
305→    // Calculate blocked tiles that would be cleared
306→    // (Check adjacent tiles to matches for blocked tiles)
307→    const matchPositions = new Set();
308→    for (const match of matches) {
309→        for (const tile of match.tiles) {
310→            matchPositions.add(`${tile.row},${tile.col}`);
311→        }
312→    }
313→
314→    // Check adjacent tiles for blocked tiles
315→    for (const match of matches) {
316→        for (const tile of match.tiles) {
317→            const adjacentPositions = [
318→                [tile.row - 1, tile.col],
319→                [tile.row + 1, tile.col],
320→                [tile.row, tile.col - 1],
321→                [tile.row, tile.col + 1],
322→            ];
323→
324→            for (const [adjRow, adjCol] of adjacentPositions) {
325→                if (adjRow >= 0 && adjRow < game.boardHeight && adjCol >= 0 && adjCol < game.boardWidth) {
326→                    const adjTile = game.board[adjRow]?.[adjCol];
327→                    if (
328→                        adjTile &&
329→                        (isBlocked(adjTile) ||
330→                            isBlockedWithLife(adjTile) ||
331→                            isBlockedMovable(adjTile) ||
332→                            isBlockedWithMergeCount(adjTile))
333→                    ) {
334→                        blockedCleared += 1;
335→                    }
336→                }
337→            }
338→        }
339→    }
340→
341→    // NOTE: If there are blocked tiles on the board, there is always a corresponding
342→    // blocked-tiles goal. So we don't need to check whether that goal is currently "open".
343→
344→    // Calculate position bonus (matches closer to bottom trigger more cascades)
345→    let totalRow = 0;
346→    let tileCount = 0;
347→    for (const match of matches) {
348→        for (const tile of match.tiles) {
349→            totalRow += tile.row;
350→            tileCount++;
351→        }
352→    }
353→    // Average row position (0 = top, boardHeight-1 = bottom)
354→    // Bonus scales from 0 to ~150 based on position
355→    const avgRow = tileCount > 0 ? totalRow / tileCount : 0;
356→    const positionBonus = Math.round((avgRow / (game.boardHeight - 1)) * 150);
