286→/**
287→ * Check if level has blocked tiles with life values
288→ * @param {Array} blockedTiles - Array of blocked tile configurations
289→ * @returns {boolean} True if any blocked tiles have life values
290→ */
291→export function hasLifeBasedBlockedTiles(blockedTiles) {
292→    if (!blockedTiles || blockedTiles.length === 0) return false;
293→    return blockedTiles.some((tile) => tile.lifeValue !== undefined);
294→}
295→
296→/**
297→ * Generate HTML for goal visuals to display in dialog
298→ * @param {Object} game - The game instance
299→ * @param {string} dialogType - The dialog type being shown
300→ * @returns {string} HTML string for goal visuals
301→ */
302→function generateGoalVisualsHTML(game, dialogType) {
303→    if (!game || !game.levelGoals) return "";
304→
305→    // Filter goals that match this dialog type
306→    const relevantGoals = game.levelGoals.filter((goal) => {
307→        if (dialogType === "created" && goal.goalType === "created") return true;
308→        if (dialogType === "current" && goal.goalType === "current") return true;
309→        if (dialogType === "blocked" && goal.goalType === "blocked" && !hasLifeBasedBlockedTiles(game.blockedTiles))
310→            return true;
311→        if (dialogType === "cursed" && goal.goalType === "cursed" && !goal.implode) return true;
312→        if (dialogType === "cursed_implode" && goal.goalType === "cursed" && goal.implode) return true;
313→        if (dialogType === "score" && goal.goalType === "score") return true;
314→        return false;
315→    });
316→
317→    if (relevantGoals.length === 0) return "";
318→
319→    // Generate goal cards HTML
320→    let goalsHTML = '<div class="goal-dialog-goals">';
321→    relevantGoals.forEach((goal) => (goalsHTML += createGoalCard(game, goal).outerHTML));
322→    goalsHTML += "</div>";
323→
324→    return goalsHTML;
325→}
326→
327→/**
328→ * Create and show a goal dialog
329→ * @param {string} dialogType - The type of dialog to show
330→ * @param {Object} game - The game instance (to access goals and display values)
331→ * @param {Function} onClose - Callback when dialog is closed
332→ */
333→export function showGoalDialog(dialogType, game, onClose) {
334→    const dialog = GOAL_DIALOGS[dialogType];
335→    if (!dialog) {
336→        console.error(`Unknown dialog type: ${dialogType}`);
337→        if (onClose) onClose();
338→        return;
339→    }
340→
341→    // Create dialog overlay
342→    const overlay = document.createElement("div");
343→    overlay.className = "goal-dialog-overlay";
344→    overlay.id = "goalDialog";
345→
346→    // Generate goal visuals HTML
347→    const goalsHTML = generateGoalVisualsHTML(game, dialogType);
348→
349→    // Create dialog content
350→    const dialogElement = document.createElement("div");
351→    dialogElement.className = "goal-dialog";
352→    dialogElement.innerHTML = `
353→        <div class="goal-dialog-header">
354→            <h2>${dialog.title}</h2>
355→            <h3>${dialog.subtitle}</h3>
356→        </div>
357→        <div class="goal-dialog-content">
358→            ${goalsHTML}
359→            ${dialog.content}
360→        </div>
361→        <div class="goal-dialog-footer">
362→            <button class="goal-dialog-button" id="goalDialogClose">Got it</button>
363→        </div>
364→    `;
365→
366→    overlay.appendChild(dialogElement);
367→    document.body.appendChild(overlay);
368→
369→    // Add close handler
370→    const closeButton = document.getElementById("goalDialogClose");
371→    closeButton.addEventListener("click", () => {
372→        overlay.classList.add("hidden");
373→        setTimeout(() => {
374→            overlay.remove();
375→        }, 300);
376→        saveShownGoalDialog(dialogType);
377→        if (onClose) onClose();
378→    });
379→
380→    // Show dialog with animation
381→    requestAnimationFrame(() => {
382→        overlay.classList.add("visible");
383→    });
384→}
385→
386→/**
387→ * Show multiple goal dialogs in sequence
388→ * @param {Array<string>} dialogTypes - Array of dialog types to show
389→ * @param {Object} game - The game instance
390→ * @param {Function} onComplete - Callback when all dialogs are closed
391→ */
392→export function showGoalDialogsSequence(dialogTypes, game, onComplete) {
393→    if (dialogTypes.length === 0) {
394→        if (onComplete) onComplete();
395→        return;
396→    }
397→
398→    let currentIndex = 0;
399→
400→    const showNext = () => {
401→        if (currentIndex >= dialogTypes.length) {
402→            if (onComplete) onComplete();
403→            return;
404→        }
405→
406→        showGoalDialog(dialogTypes[currentIndex], game, () => {
407→            currentIndex++;
408→            // Small delay between dialogs
409→            setTimeout(showNext, 300);
410→        });
411→    };
412→
413→    showNext();
414→}
415→
416→/**
417→ * Check if feature has been unlocked
418→ * @param {string} featureKey - The feature key to check
419→ * @returns {boolean} True if the feature has been unlocked
420→ */
421→export function hasFeatureBeenUnlocked(featureKey) {
422→    return isFeatureUnlocked(featureKey);
423→}
424→
425→/**
426→ * Show feature unlock dialog
427→ * @param {string} featureKey - The feature key to unlock
428→ * @param {Object} game - The game instance
429→ * @param {Function} onClose - Callback when dialog is closed
430→ */
431→export function showFeatureUnlockDialog(featureKey, game, onClose) {
432→    // Resolve power_up_N keys to actual power-up type from game's selected power-ups
433→    let dialog = FEATURE_UNLOCK_DIALOGS[featureKey];
434→    if (!dialog && featureKey.startsWith("power_up_")) {
435→        const slotIndex = parseInt(featureKey.split("_")[2]) - 1;
436→        const powerUpType = game.selectedPowerUps[slotIndex];
437→        if (powerUpType) {
438→            dialog = buildPowerUpDialog(powerUpType);
439→        }
440→    }
441→    if (!dialog) {
442→        console.warn(`Unknown feature: ${featureKey}`);
443→        if (onClose) onClose();
444→        return;
445→    }
446→
447→    // Create dialog overlay
448→    const overlay = document.createElement("div");
449→    overlay.className = "goal-dialog-overlay";
450→    overlay.id = "featureUnlockDialog";
451→
452→    // Create dialog content
453→    const dialogElement = document.createElement("div");
454→    dialogElement.className = "goal-dialog";
455→    dialogElement.innerHTML = `
456→        <div class="goal-dialog-header">
457→            <h2>${dialog.title}</h2>
458→            <h3>${dialog.subtitle}</h3>
459→        </div>
460→        <div class="goal-dialog-content">
461→            ${dialog.content}
462→        </div>
463→        <div class="goal-dialog-footer">
464→            <button class="goal-dialog-button">Got it!</button>
465→        </div>
466→    `;
467→
468→    overlay.appendChild(dialogElement);
469→    document.body.appendChild(overlay);
470→
471→    // Add close handler - use querySelector on the overlay instead of getElementById
472→    const closeButton = overlay.querySelector(".goal-dialog-button");
473→    closeButton.addEventListener("click", () => {
474→        overlay.classList.add("hidden");
475→        setTimeout(() => overlay.remove(), 300);
476→        if (onClose) onClose();
477→    });
478→
479→    // Show with animation
480→    requestAnimationFrame(() => {
481→        overlay.classList.add("visible");
482→    });
483→}
484→
485→/**
486→ * Populate the intro dialog power-ups list based on which power-ups have been unlocked
487→ */
488→export function updateIntroDialogPowerupsList(game) {
489→    const powerupList = document.getElementById("powerupList");
490→    const powerupsSection = document.getElementById("powerupsSection");
491→    if (!powerupList || !powerupsSection) return;
492→
493→    // Clear existing list
494→    powerupList.innerHTML = "";
495→
496→    // Get visible (selected + unlocked) power-up types from game
497→    const visibleTypes = game.getVisiblePowerUpTypes();
498→
499→    if (visibleTypes.length === 0) {
500→        powerupsSection.style.display = "none";
501→        return;
502→    }
503→
504→    powerupsSection.style.display = "block";
505→
506→    visibleTypes.forEach((type) => {
507→        const info = POWER_UP_INFO[type];
508→        if (!info) return;
509→        const powerupItem = document.createElement("div");
510→        powerupItem.className = "powerup-item";
511→        powerupItem.innerHTML = `
512→            <span class="powerup-icon">${info.icon}</span>
513→            <div class="powerup-info">
514→                <strong>${info.name}</strong><br />
515→                ${info.description}
516→            </div>
517→        `;
518→        powerupList.appendChild(powerupItem);
519→    });
520→}
