        const gameBoard = document.getElementById("gameBoard");

        if (gameBoard) {
            gameBoard.classList.remove("level-ended");
        }
        if (levelSolvedSvg) {
            levelSolvedSvg.style.visibility = "hidden";
            levelSolvedSvg.classList.remove("animate");
        }
