.power-up-btn {
    width: clamp(60px, 20vw, 120px);
    height: clamp(60px, 20vw, 120px);
    border-radius: 24px;
    border: 4px solid #000;
    background: #141414;
    color: white;
    font-size: clamp(16px, 8vw, 50px);
    cursor: pointer;
    backdrop-filter: blur(10px);
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
}

.power-up-btn.disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* Locked power-up styling */
.power-up-btn.locked {
    opacity: 0;
    filter: grayscale(100%);
    cursor: not-allowed;
    position: relative;
    display: none;
}

.power-up-btn.active {
    background: #aee96b;
    box-shadow: 0 -6px 0 0 rgba(0, 0, 0, 0.25) inset;
}

